class Solution {
    public int[] validSequence(String word1, String word2) {
        int n = word1.length(), m = word2.length();
        int[] res = new int[m];
        int[] idx = new int[n];
        for (int i = 0; i < n; i++) idx[i] = i;
        Arrays.sort(idx, (a, b) -> word1.charAt(a) == word1.charAt(b) ? a - b : word1.charAt(a) - word1.charAt(b));
        int j = 0;
        for (int i = 0; i < n; i++) {
            if (word1.charAt(idx[i]) == word2.charAt(j)) {
                res[j] = idx[i];
                j++;
            }
            if (j == m) break;
        }
        if (j != m) return new int[0];
        int diff = 0;
        for (int i = 0; i < m; i++) {
            if (word1.charAt(res[i]) != word2.charAt(i)) diff++;
        }
        if (diff > 1) return new int[0];
        return res;
    }
}
